output.sparql:
SELECT ?performer WHERE {
  ?episode wdt:P154 wd:Q13979 ;
          wdt:P585 ?date ;
          wdt:P175 ?performer .
  FILTER (isLiteral(?date) && ?date > "2023-10-01"^^xsd:date)
  ORDER BY DESC(?date)
  LIMIT 1
}

